CREATE TABLE IF NOT EXISTS inspection_surface_events (
    inspection_event_id TEXT PRIMARY KEY,
    coil_no TEXT NOT NULL,
    device_code TEXT NOT NULL,
    defect_type TEXT NOT NULL,
    severity TEXT NOT NULL,
